from lxml import etree

def process_soap_request(xml_request):
    # Define DTD
    dtd = etree.DTD(open('path_to_your_dtd_file.dtd'))
    
    # Parse the SOAP request with DTD validation
    try:
        doc = etree.fromstring(xml_request, parser=etree.XMLParser(load_dtd=True))
        if not dtd.validate(doc):
            raise ValueError("DTD validation failed")
    except etree.XMLSyntaxError as e:
        raise ValueError(f"XML parsing error: {e}")
    
    # Extract SOAP Envelope and Body
    envelope = doc.find('{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
    if envelope is None:
        raise ValueError("SOAP Envelope not found")
    
    body = envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if body is None:
        raise ValueError("SOAP Body not found")
    
    return etree.tostring(body, pretty_print=True).decode('utf-8')

